 16	interface OutputEnvelope {
 17	  command: string;
 18	  version: 1;
 19	  status: CliStatus;
 20	  outcome: string;
 21	  result?: unknown;
 22	  errors: CliError[];
 23	  warnings: string[];
 24	  artifacts: CliArtifactRef[];
 25	  startedAt: string;
 26	  finishedAt: string;
 27	}
 28	
 29	function renderHumanSummary(envelope: OutputEnvelope) {
 30	  if (
 31	    typeof envelope.result !== "object" ||
 32	    envelope.result === null ||
 33	    !("techDesignShape" in envelope.result)
 34	  ) {
 35	    return `inspect: ${envelope.outcome}`;
 36	  }
 37	
 38	  const result = envelope.result as InspectResult;
 39	  const lines = [
 40	    `inspect: ${envelope.outcome}`,
 41	    `tech design: ${result.techDesignShape}`,
 42	    `stories: ${result.stories.length}`,
 43	    `impl insert: ${result.inserts.customStoryImplPromptInsert}`,
 44	    `verifier insert: ${result.inserts.customStoryVerifierPromptInsert}`,
 45	  ];
 46	
 47	  if (result.blockers.length > 0) {
 48	    lines.push(...result.blockers.map((blocker) => `blocker: ${blocker}`));
 49	  }
 50	
 51	  return lines.join("\n");
 52	}
 53	
 54	function emitOutput(params: {
 55	  envelope: OutputEnvelope;
 56	  json: boolean;
 57	}) {
 58	  if (params.json) {
 59	    console.log(JSON.stringify(params.envelope));
 60	    return;
 61	  }
 62	
 63	  console.log(renderHumanSummary(params.envelope));
 64	}
 65	
 66	function inspectErrors(result: InspectResult): CliError[] {
 67	  if (result.status !== "blocked") {
 68	    return [];
 69	  }
 70	
 71	  if (
 72	    result.blockers.some((blocker) =>
 73	      blocker.startsWith("Unreadable prompt insert:")
 74	    )
 75	  ) {
 76	    return [
 77	      {
 78	        code: "PROMPT_INSERT_INVALID",
 79	        message: "Prompt insert inspection failed",
 80	      },
 81	    ];
 82	  }
 83	
 84	  return [
 85	    {
 86	      code: "INVALID_SPEC_PACK",
 87	      message: "Spec-pack inspection failed",
 88	    },
 89	  ];
 90	}
