 92	export default defineCommand({
 93	  meta: {
 94	    name: "inspect",
 95	    description: "Resolve the spec-pack layout, tech-design shape, and public insert files.",
 96	  },
 97	  args: {
 98	    "spec-pack-root": {
 99	      type: "string",
100	      description: "Absolute or relative path to the spec-pack root",
101	      required: true,
102	    },
103	    json: {
104	      type: "boolean",
105	      description: "Emit the structured JSON envelope on stdout",
106	    },
107	  },
108	  async run({ args }) {
109	    const startedAt = new Date().toISOString();
110	
111	    try {
112	      const inspectResult = await inspectSpecPack(args["spec-pack-root"]);
113	      const artifactPath = await nextArtifactPath(
114	        inspectResult.specPackRoot,
115	        "inspect"
116	      );
117	      const envelope = cliResultEnvelopeSchema(inspectResultSchema).parse(
118	        createResultEnvelope({
119	          command: "inspect",
120	          outcome: inspectResult.status,
121	          result: inspectResult,
122	          errors: inspectErrors(inspectResult),
123	          artifacts: [
124	            {
125	              kind: "result-envelope",
126	              path: artifactPath,
127	            },
128	          ],
129	          startedAt,
130	          finishedAt: new Date().toISOString(),
131	        })
132	      );
133	
134	      await writeJsonArtifact(artifactPath, envelope);
135	      emitOutput({
136	        envelope,
137	        json: Boolean(args.json),
138	      });
139	      process.exitCode = exitCodeForStatus(envelope.status);
140	    } catch (error) {
141	      const envelope: OutputEnvelope = createResultEnvelope({
142	        command: "inspect",
143	        outcome: "error",
144	        errors: [
145	          {
146	            code: "UNEXPECTED_ERROR",
147	            message: error instanceof Error ? error.message : String(error),
148	          },
149	        ],
150	        startedAt,
151	        finishedAt: new Date().toISOString(),
152	      });
153	
154	      emitOutput({
155	        envelope,
156	        json: Boolean(args.json),
157	      });
158	      process.exitCode = exitCodeForStatus(envelope.status);
159	    }
160	  },
161	});

  1	import { readdir, stat } from "node:fs/promises";
  2	import { basename, join, resolve } from "node:path";
  3	
  4	import { inspectResultSchema, type InspectResult } from "./result-contracts";
  5	import { pathExists, pathReadable, readTextFile } from "./fs-utils";
  6	import { resolveGitRepoRoot } from "./git-repo";
  7	
  8	const ALLOWED_TECH_DESIGN_COMPANIONS = [
  9	  "tech-design-cli-runtime.md",
 10	  "tech-design-skill-process.md",
 11	] as const;
 12	
 13	interface StoryRecord {
 14	  id: string;
 15	  title: string;
 16	  path: string;
 17	  order: number;
 18	}
 19	
 20	async function pathIsDirectory(path: string): Promise<boolean> {
 21	  try {
 22	    return (await stat(path)).isDirectory();
 23	  } catch {
 24	    return false;
 25	  }
 26	}
 27	
 28	function extractStoryTitle(content: string, fallback: string): string {
 29	  const match = content.match(/^#\s+(.+)$/m);
 30	  return match?.[1]?.trim() || fallback;
 31	}
 32	
 33	function storySortKey(fileName: string): [number, string] {
 34	  const match = fileName.match(/^(\d+)-/);
 35	  return [match ? Number(match[1]) : Number.MAX_SAFE_INTEGER, fileName];
 36	}
 37	
 38	async function readStoryInventory(storiesDir: string): Promise<StoryRecord[]> {
 39	  const entries = await readdir(storiesDir, { withFileTypes: true });
 40	  const fileNames = entries
 41	    .filter((entry) => entry.isFile() && entry.name.endsWith(".md"))
 42	    .map((entry) => entry.name)
 43	    .filter((fileName) => fileName !== "coverage.md")
 44	    .sort((left, right) => {
 45	      const [leftPrefix, leftName] = storySortKey(left);
 46	      const [rightPrefix, rightName] = storySortKey(right);
 47	      if (leftPrefix !== rightPrefix) {
 48	        return leftPrefix - rightPrefix;
 49	      }
 50	      return leftName.localeCompare(rightName);
 51	    });
 52	
 53	  const stories: StoryRecord[] = [];
 54	
 55	  for (const [index, fileName] of fileNames.entries()) {
 56	    const path = join(storiesDir, fileName);
 57	    const content = await readTextFile(path);
 58	    stories.push({
 59	      id: basename(fileName, ".md"),
 60	      title: extractStoryTitle(content, basename(fileName, ".md")),
 61	      path,
 62	      order: index + 1,
 63	    });
 64	  }
 65	
 66	  return stories;
 67	}
