 69	function resolveTechDesignArtifacts(entries: string[]): {
 70	  techDesignShape: "two-file" | "four-file";
 71	  companionPaths: string[];
 72	  blockers: string[];
 73	} {
 74	  const companionFiles = entries
 75	    .filter(
 76	      (entry) =>
 77	        entry.startsWith("tech-design-") &&
 78	        entry.endsWith(".md") &&
 79	        entry !== "tech-design.md"
 80	    )
 81	    .sort((left, right) => left.localeCompare(right));
 82	
 83	  if (companionFiles.length === 0) {
 84	    return {
 85	      techDesignShape: "two-file",
 86	      companionPaths: [],
 87	      blockers: [],
 88	    };
 89	  }
 90	
 91	  const allowed = [...ALLOWED_TECH_DESIGN_COMPANIONS].sort((left, right) =>
 92	    left.localeCompare(right)
 93	  );
 94	
 95	  if (JSON.stringify(companionFiles) === JSON.stringify(allowed)) {
 96	    return {
 97	      techDesignShape: "four-file",
 98	      companionPaths: companionFiles,
 99	      blockers: [],
100	    };
101	  }
102	
103	  return {
104	    techDesignShape: "two-file",
105	    companionPaths: [],
106	    blockers: [
107	      "Invalid tech-design companion layout: expected tech-design-cli-runtime.md and tech-design-skill-process.md for the four-file configuration",
108	    ],
109	  };
110	}
