112	export async function inspectSpecPack(specPackRoot: string): Promise<InspectResult> {
113	  const resolvedRoot = resolve(specPackRoot);
114	  const epicPath = join(resolvedRoot, "epic.md");
115	  const techDesignPath = join(resolvedRoot, "tech-design.md");
116	  const testPlanPath = join(resolvedRoot, "test-plan.md");
117	  const storiesDir = join(resolvedRoot, "stories");
118	  const storiesFile = join(resolvedRoot, "stories.md");
119	  const blockers: string[] = [];
120	  const notes: string[] = [];
121	
122	  const repoRoot = await resolveGitRepoRoot(resolvedRoot);
123	  if (!repoRoot) {
124	    blockers.push(`Spec-pack root is not inside a git repo: ${resolvedRoot}`);
125	  }
126	
127	  if (!(await pathExists(epicPath))) {
128	    blockers.push("Missing required artifact: epic.md");
129	  }
130	
131	  if (!(await pathExists(techDesignPath))) {
132	    blockers.push("Missing required artifact: tech-design.md");
133	  }
134	
135	  if (!(await pathExists(testPlanPath))) {
136	    blockers.push("Missing required artifact: test-plan.md");
137	  }
138	
139	  const storiesDirExists = await pathIsDirectory(storiesDir);
140	  if (!storiesDirExists && (await pathExists(storiesFile))) {
141	    blockers.push("Expected stories/ directory but found stories.md");
142	  } else if (!storiesDirExists) {
143	    blockers.push("Missing required artifact: stories/");
144	  }
145	
146	  const rootEntries = await readdir(resolvedRoot);
147	  const techDesignArtifacts = resolveTechDesignArtifacts(rootEntries);
148	  blockers.push(...techDesignArtifacts.blockers);
149	
150	  const stories = storiesDirExists ? await readStoryInventory(storiesDir) : [];
151	  const implInsertPath = join(
152	    resolvedRoot,
153	    "custom-story-impl-prompt-insert.md"
154	  );
155	  const verifierInsertPath = join(
156	    resolvedRoot,
157	    "custom-story-verifier-prompt-insert.md"
158	  );
159	  const implInsertExists = await pathExists(implInsertPath);
160	  const verifierInsertExists = await pathExists(verifierInsertPath);
161	
162	  if (implInsertExists && !(await pathReadable(implInsertPath))) {
163	    blockers.push(
164	      "Unreadable prompt insert: custom-story-impl-prompt-insert.md"
165	    );
166	  }
167	
168	  if (verifierInsertExists && !(await pathReadable(verifierInsertPath))) {
169	    blockers.push(
170	      "Unreadable prompt insert: custom-story-verifier-prompt-insert.md"
171	    );
172	  }
173	
174	  const result: InspectResult = {
175	    status: blockers.length > 0 ? "blocked" : "ready",
176	    specPackRoot: resolvedRoot,
177	    techDesignShape: techDesignArtifacts.techDesignShape,
178	    artifacts: {
179	      epicPath,
180	      techDesignPath,
181	      techDesignCompanionPaths: techDesignArtifacts.companionPaths.map((file) =>
182	        join(resolvedRoot, file)
183	      ),
184	      testPlanPath,
185	      storiesDir,
186	    },
187	    stories,
188	    inserts: {
189	      customStoryImplPromptInsert: implInsertExists
190	        ? "present"
191	        : "absent",
192	      customStoryVerifierPromptInsert: verifierInsertExists
193	        ? "present"
194	        : "absent",
195	    },
196	    blockers,
197	    notes,
198	  };
199	
200	  return inspectResultSchema.parse(result);
201	}

  1	import { z } from "zod";
  2	
  3	export const cliErrorSchema = z.object({
  4	  code: z.string().min(1),
  5	  message: z.string().min(1),
  6	  detail: z.string().min(1).optional(),
  7	});
  8	
  9	export const cliArtifactRefSchema = z.object({
 10	  kind: z.string().min(1),
 11	  path: z.string().min(1),
 12	});
 13	
 14	export const cliStatusSchema = z.enum([
 15	  "ok",
 16	  "needs-user-decision",
 17	  "blocked",
 18	  "error",
 19	]);
 20	
 21	export const inspectOutcomeSchema = z.enum([
 22	  "ready",
 23	  "needs-user-decision",
 24	  "blocked",
 25	]);
 26	
 27	export const inspectResultSchema = z.object({
 28	  status: inspectOutcomeSchema,
 29	  specPackRoot: z.string().min(1),
 30	  techDesignShape: z.enum(["two-file", "four-file"]),
 31	  artifacts: z.object({
 32	    epicPath: z.string().min(1),
 33	    techDesignPath: z.string().min(1),
 34	    techDesignCompanionPaths: z.array(z.string().min(1)),
 35	    testPlanPath: z.string().min(1),
 36	    storiesDir: z.string().min(1),
 37	  }),
 38	  stories: z.array(
 39	    z.object({
 40	      id: z.string().min(1),
 41	      title: z.string().min(1),
 42	      path: z.string().min(1),
 43	      order: z.number().int().positive(),
 44	    })
 45	  ),
 46	  inserts: z.object({
 47	    customStoryImplPromptInsert: z.enum(["present", "absent"]),
 48	    customStoryVerifierPromptInsert: z.enum(["present", "absent"]),
 49	  }),
 50	  blockers: z.array(z.string()),
 51	  notes: z.array(z.string()),
 52	});
 53	
 54	export type CliError = z.infer<typeof cliErrorSchema>;
 55	export type CliArtifactRef = z.infer<typeof cliArtifactRefSchema>;
 56	export type CliStatus = z.infer<typeof cliStatusSchema>;
 57	export type InspectOutcome = z.infer<typeof inspectOutcomeSchema>;
 58	export type InspectResult = z.infer<typeof inspectResultSchema>;
 59	
 60	function statusForOutcome(outcome: string): CliStatus {
 61	  switch (outcome) {
 62	    case "ready":
 63	      return "ok";
 64	    case "needs-user-decision":
 65	      return "needs-user-decision";
 66	    case "blocked":
 67	      return "blocked";
 68	    default:
 69	      return "error";
 70	  }
 71	}
 72	
 73	export function exitCodeForStatus(status: CliStatus): number {
 74	  switch (status) {
 75	    case "ok":
 76	      return 0;
 77	    case "needs-user-decision":
 78	      return 2;
 79	    case "blocked":
 80	      return 3;
 81	    case "error":
 82	    default:
 83	      return 1;
 84	  }
 85	}
 86	
 87	export function cliResultEnvelopeSchema<T extends z.ZodTypeAny>(resultSchema: T) {
 88	  return z
 89	    .object({
 90	      command: z.string().min(1),
 91	      version: z.literal(1),
 92	      status: cliStatusSchema,
 93	      outcome: z.string().min(1),
 94	      result: resultSchema.optional(),
 95	      errors: z.array(cliErrorSchema),
 96	      warnings: z.array(z.string()),
 97	      artifacts: z.array(cliArtifactRefSchema),
 98	      startedAt: z.string().min(1),
 99	      finishedAt: z.string().min(1),
100	    })
101	    .superRefine((value, ctx) => {
102	      const expectedStatus = statusForOutcome(value.outcome);
103	      if (expectedStatus !== value.status) {
104	        ctx.addIssue({
105	          code: z.ZodIssueCode.custom,
106	          message: `Envelope status '${value.status}' does not match outcome '${value.outcome}'`,
107	          path: ["status"],
108	        });
109	      }
110	    });
111	}
112	
113	export function createResultEnvelope<T>(input: {
114	  command: string;
115	  outcome: string;
116	  result?: T;
117	  errors?: CliError[];
118	  warnings?: string[];
119	  artifacts?: CliArtifactRef[];
120	  startedAt: string;
121	  finishedAt: string;
122	}) {
123	  return {
124	    command: input.command,
125	    version: 1 as const,
126	    status: statusForOutcome(input.outcome),
127	    outcome: input.outcome,
128	    result: input.result,
129	    errors: input.errors ?? [],
130	    warnings: input.warnings ?? [],
131	    artifacts: input.artifacts ?? [],
132	    startedAt: input.startedAt,
133	    finishedAt: input.finishedAt,
134	  };
135	}

