 6	export async function nextArtifactPath(
 7	  specPackRoot: string,
 8	  command: string
 9	): Promise<string> {
10	  const artifactDir = join(resolve(specPackRoot), "artifacts", command);
11	  await mkdir(artifactDir, { recursive: true });
12	
13	  const entries = await readdir(artifactDir, { withFileTypes: true });
14	  const existingCount = entries.filter(
15	    (entry) => entry.isFile() && entry.name.endsWith(".json")
16	  ).length;
17	  const nextIndex = String(existingCount + 1).padStart(3, "0");
18	
19	  return join(artifactDir, `${nextIndex}-${command}.json`);
20	}
