 6	export async function resolveGitRepoRoot(
 7	  cwd: string
 8	): Promise<string | null> {
 9	  try {
10	    const { stdout } = await execFileAsync("git", ["rev-parse", "--show-toplevel"], {
11	      cwd,
12	    });
13	    const repoRoot = stdout.trim();
14	    return repoRoot.length > 0 ? repoRoot : null;
15	  } catch {
16	    return null;
17	  }
18	}

