 81	async function readSourceFile(relativePath: string): Promise<string> {
 82	  const fullPath = join(SRC, relativePath);
 83	  const file = Bun.file(fullPath);
 84	  const exists = await file.exists();
 85	  if (!exists) {
 86	    console.error(`ERROR: Source file not found: ${fullPath}`);
 87	    process.exit(1);
 88	  }
 89	  return file.text();
