 92	/**
 93	 * Extract the first top-level heading from markdown content.
 94	 * Falls back to the filename-derived title if no heading is found.
 95	 */
 96	function extractTitle(content: string, fallback: string): string {
 97	  const match = content.match(/^#\s+(.+)$/m);
 98	  return match ? match[1].trim() : fallback;
 99	}
