108	/**
109	 * Strip YAML frontmatter from composed content for standalone output.
110	 */
111	function stripFrontmatter(content: string): string {
112	  const fmRegex = /^---\n[\s\S]*?\n---\n*/;
113	  return content.replace(fmRegex, "").trimStart();
114	}
