139	async function composeSkill(skill: SkillEntry): Promise<string> {
140	  const parts: string[] = [];
141	
142	  // 1. YAML frontmatter
143	  parts.push(buildFrontmatter(skill.name, skill.description));
144	  parts.push("");
145	
146	  // 2. Phase content
147	  for (const phase of skill.phases) {
148	    const content = await readSourceFile(`phases/${phase}.md`);
149	    parts.push(content.trimEnd());
150	  }
151	
152	  // 3. Shared content
153	  for (const shared of skill.shared) {
154	    const content = await readSourceFile(`shared/${shared}.md`);
155	    const title = extractTitle(content, shared);
156	    parts.push("");
157	    parts.push("---");
158	    parts.push("");
159	    parts.push(`## Reference: ${title}`);
160	    parts.push("");
161	    parts.push(content.trimEnd());
162	  }
163	
164	  // 4. Templates (optional)
165	  if (skill.templates && skill.templates.length > 0) {
166	    for (const template of skill.templates) {
167	      const content = await readSourceFile(`templates/${template}.md`);
168	      parts.push("");
169	      parts.push("---");
170	      parts.push("");
171	      parts.push("## Template");
172	      parts.push("");
173	      parts.push(content.trimEnd());
174	    }
175	  }
176	
177	  // 5. Examples (optional)
178	  if (skill.examples && skill.examples.length > 0) {
179	    for (const example of skill.examples) {
180	      const content = await readSourceFile(`examples/${example}.md`);
181	      parts.push("");
182	      parts.push("---");
183	      parts.push("");
184	      parts.push("## Verification Prompt");
185	      parts.push("");
186	      parts.push(content.trimEnd());
187	    }
188	  }
189	
190	  // Final newline
191	  parts.push("");
192	  return parts.join("\n");
193	}
