299	async function build(): Promise<void> {
300	  // Read manifest
301	  const manifestPath = join(ROOT, "manifest.json");
302	  const manifestFile = Bun.file(manifestPath);
303	  if (!(await manifestFile.exists())) {
304	    console.error("ERROR: manifest.json not found at project root");
305	    process.exit(1);
306	  }
307	  const manifest: Manifest = await manifestFile.json();
308	
309	  const skillSummary: { name: string; lines: number }[] = [];
310	
311	  // Create output directories
312	  await mkdir(DIST_SKILLS, { recursive: true });
313	  await mkdir(DIST_STANDALONE, { recursive: true });
314	  await mkdir(SKILL_PACK_DIR, { recursive: true });
315	  await mkdir(MARKDOWN_PACK_DIR, { recursive: true });
316	  await ensureBundledArtifacts(manifest);
317	
318	  // ----- Skills -----
319	  for (const [key, skill] of Object.entries(manifest.skills)) {
320	    const composed = await composeSkill(skill);
321	    const lineCount = composed.split("\n").length;
322	
323	    // Skill directory output (installable)
324	    const skillDir = join(DIST_SKILLS, key);
325	    await mkdir(skillDir, { recursive: true });
326	    await Bun.write(join(skillDir, "SKILL.md"), composed);
327	    await copyBundledMarkdownFiles("references", skill.references, skillDir);
328	    await copyBundledArtifacts(skill.bundledArtifacts, skillDir);
329	
330	    // Standalone .md output (no frontmatter, for paste-into-chat)
331	    const standalone = stripFrontmatter(composed);
332	    const standaloneName = STANDALONE_NAMES[key] ?? key;
333	    const mdFileName = `${standaloneName}-skill.md`;
334	    await Bun.write(join(DIST_STANDALONE, mdFileName), standalone + "\n");
335	    await Bun.write(join(MARKDOWN_PACK_DIR, mdFileName), standalone + "\n");
336	
337	    // Skill-pack content (directory with SKILL.md per skill)
338	    const skillPkgDir = join(SKILL_PACK_DIR, key);
339	    await mkdir(skillPkgDir, { recursive: true });
340	    await Bun.write(join(skillPkgDir, "SKILL.md"), composed);
341	    await copyBundledMarkdownFiles("references", skill.references, skillPkgDir);
342	    await copyBundledArtifacts(skill.bundledArtifacts, skillPkgDir);
343	
344	    skillSummary.push({ name: key, lines: lineCount });
345	    console.log(`  skill: ${key} (${lineCount} lines)`);
346	  }
347	
348	  // Copy READMEs into pack staging directories
349	  const skillReadme = await Bun.file(join(SRC, "README-pack.md")).text();
350	  const markdownReadme = await Bun.file(join(SRC, "README-markdown-pack.md")).text();
351	  await Bun.write(join(SKILL_PACK_DIR, "liminal-spec-skillpack-readme.md"), skillReadme);
352	  await Bun.write(join(MARKDOWN_PACK_DIR, "README.md"), markdownReadme);
353	
354	  // Create packs
355	  await zipDirectory(SKILL_PACK_ZIP_NAME, SKILL_PACK_DIR_NAME, DIST_STANDALONE);
356	  await zipDirectory(MARKDOWN_PACK_ZIP_NAME, MARKDOWN_PACK_DIR_NAME, DIST_STANDALONE);
357	  console.log(`  skill pack: ${SKILL_PACK_ZIP}`);
358	  console.log(`  markdown pack: ${MARKDOWN_PACK_ZIP}`);
359	
360	  // Clean up pack staging directories
361	  await rm(SKILL_PACK_DIR, { recursive: true, force: true });
362	  await rm(MARKDOWN_PACK_DIR, { recursive: true, force: true });
363	
364	  // ----- Summary -----
365	  console.log("\nBuild complete:");
366	  console.log(
367	    `  ${skillSummary.length} skills composed (${skillSummary.map((s) => `${s.name}: ${s.lines} lines`).join(", ")})`
368	  );
369	}
370	
371	build().catch((err: unknown) => {
372	  console.error("Build failed:", err);
373	  process.exit(1);
374	});

  1	/**
  2	 * Validate script for liminal-spec skill pack.
  3	 *
  4	 * Checks dist/ output for structural correctness:
  5	 *   - Skill files have valid YAML frontmatter
  6	 *   - Bundled reference files exist when declared in manifest.json
  7	 *   - Standalone files exist and lack frontmatter
  8	 *   - Pack zips exist and are non-empty
  9	 *   - manifest.json conforms to schema
 10	 *
 11	 * Optional environment variables:
 12	 *   DIST_DIR -- output root directory to validate (default: dist)
 13	 */
 14	
 15	import { isAbsolute, join, resolve } from "node:path";
 16	import { z } from "zod";
 17	import { Glob } from "bun";
 18	
 19	// ---------------------------------------------------------------------------
 20	// Lightweight frontmatter parser
 21	// ---------------------------------------------------------------------------
 22	
 23	interface ParsedFrontmatter {
 24	  data: Record<string, unknown>;
 25	  content: string;
 26	}
 27	
 28	function parseFrontmatter(raw: string): ParsedFrontmatter {
 29	  if (!raw.startsWith("---\n")) {
 30	    return { data: {}, content: raw };
 31	  }
 32	  const endIndex = raw.indexOf("\n---", 3);
 33	  if (endIndex === -1) {
 34	    return { data: {}, content: raw };
 35	  }
 36	  const yamlBlock = raw.slice(4, endIndex);
 37	  const content = raw.slice(endIndex + 4).trimStart();
 38	  const data: Record<string, unknown> = {};
 39	  const lines = yamlBlock.split("\n");
 40	  let currentKey = "";
 41	  let currentValue = "";
 42	  let inMultiline = false;
 43	
 44	  for (const line of lines) {
 45	    if (inMultiline) {
 46	      if (line.startsWith("  ") || line === "") {
 47	        currentValue += (currentValue ? "\n" : "") + line.replace(/^  /, "");
 48	      } else {
 49	        data[currentKey] = currentValue.trim();
 50	        inMultiline = false;
 51	      }
 52	    }
 53	    if (!inMultiline) {
 54	      const match = line.match(/^(\w[\w-]*):\s*(.*)/);
 55	      if (match) {
 56	        currentKey = match[1];
 57	        const val = match[2];
 58	        if (val === "|" || val === ">") {
 59	          inMultiline = true;
 60	          currentValue = "";
 61	        } else {
 62	          data[currentKey] = val;
 63	        }
 64	      }
 65	    }
 66	  }
 67	  if (inMultiline && currentKey) {
 68	    data[currentKey] = currentValue.trim();
 69	  }
 70	  return { data, content };
 71	}
