 77	const ROOT = resolve(import.meta.dir, "..");
 78	const DIST_DIR = process.env.DIST_DIR?.trim() || "dist";
 79	const DIST = isAbsolute(DIST_DIR) ? DIST_DIR : join(ROOT, DIST_DIR);
