 88	
 89	const SemverSchema = z.string().regex(
 90	  /^\d+\.\d+\.\d+(-[\w.]+)?$/,
 91	  "version must be valid semver (e.g. 1.0.0)"
 92	);
 93	
 94	const SkillSchema = z.object({
 95	  name: z.string().min(1),
 96	  description: z.string().min(1),
 97	  phases: z.array(z.string().min(1)).min(1),
 98	  shared: z.array(z.string().min(1)),
 99	  references: z.array(z.string().min(1)).optional(),
100	  templates: z.array(z.string().min(1)).optional(),
101	  examples: z.array(z.string().min(1)).optional(),
102	  bundledArtifacts: z
103	    .array(
104	      z.object({
105	        source: z.string().min(1),
106	        destination: z.string().min(1),
107	      })
108	    )
109	    .optional(),
110	});
111	
112	const ManifestSchema = z.object({
113	  version: SemverSchema,
114	  skills: z.record(z.string(), SkillSchema),
115	});
